"use client";

import { useMemo, useState } from "react";
import type { SiteContent } from "@/lib/content-data";
import type { AdminEntity } from "@/lib/content-store";

const labels: Record<AdminEntity, string> = { projects: "Projeler", slides: "Ana Sayfa Slaytı", settings: "Site ve Logolar", services: "Hizmetler", references: "Referanslar", fleet: "Makine Parkı" };

function blank(entity: AdminEntity): Record<string, unknown> {
  const id = crypto.randomUUID();
  if (entity === "projects") return { id, title: "", slug: "", summary: "", description: "", location: "", client: "", status: "ongoing", startDate: new Date().toISOString().slice(0, 10), endDate: "", year: new Date().getFullYear(), coverImageUrl: "", galleryUrls: [], youtubeUrl: "", projectWebsiteUrl: "", featured: false, sortOrder: 0 };
  if (entity === "services") return { id, number: "01", title: "", summary: "", sortOrder: 0 };
  if (entity === "references") return { id, name: "", logoUrl: "", websiteUrl: "", featured: false, sortOrder: 0 };
  if (entity === "slides") return { id, imageUrl: "", altText: "", active: true, sortOrder: 0 };
  if (entity === "settings") return { id: "homepage" };
  return { id, name: "", category: "", brandModel: "", quantity: 0, verified: false, imageUrl: "", sortOrder: 0 };
}

async function optimizeImage(file: File, logo = false) {
  if (file.type === "image/svg+xml" || file.type === "image/gif") return file;
  try {
  const bitmap = await createImageBitmap(file);
  const maxWidth = logo ? 1400 : 1920;
  const maxHeight = logo ? 900 : 1440;
  const scale = Math.min(1, maxWidth / bitmap.width, maxHeight / bitmap.height);
  const canvas = document.createElement("canvas");
  canvas.width = Math.max(1, Math.round(bitmap.width * scale));
  canvas.height = Math.max(1, Math.round(bitmap.height * scale));
  const context = canvas.getContext("2d");
  if (!context) return file;
  context.drawImage(bitmap, 0, 0, canvas.width, canvas.height);
  bitmap.close();
  const blob = await new Promise<Blob | null>((resolve) => canvas.toBlob(resolve, "image/webp", logo ? 0.9 : 0.82));
  if (!blob || blob.size >= file.size) return file;
  return new File([blob], file.name.replace(/\.[^.]+$/, "") + ".webp", { type: "image/webp" });
  } catch { return file; }
}

export function AdminPanel({ initialContent }: { initialContent: SiteContent }) {
  const [content, setContent] = useState(initialContent);
  const [entity, setEntity] = useState<AdminEntity>("projects");
  const [form, setForm] = useState<Record<string, unknown>>(() => ({ ...initialContent.projects[0] }));
  const [message, setMessage] = useState("");
  const [busy, setBusy] = useState(false);
  const [draggedId, setDraggedId] = useState<string | null>(null);
  const items = useMemo(() => entity === "settings" ? [content.settings as unknown as Record<string, unknown>] : content[entity] as unknown as Record<string, unknown>[], [content, entity]);

  function chooseEntity(next: AdminEntity) { setEntity(next); const nextItems = next === "settings" ? [content.settings as unknown as Record<string, unknown>] : content[next] as unknown as Record<string, unknown>[]; setForm(nextItems[0] ? { ...nextItems[0] } : blank(next)); setMessage(""); }
  function field(name: string, value: unknown) { setForm((current) => ({ ...current, [name]: value })); }
  const text = (name: string) => String(form[name] ?? "");
  const num = (name: string) => Number(form[name] ?? 0);

  async function upload(files: FileList | null, fieldName: string, multiple = false, logo = false, preserveOriginal = false) {
    if (!files?.length) return;
    setBusy(true); setMessage("Görseller yükleniyor…");
    try {
      const urls: string[] = [];
      for (const [index, file] of Array.from(files).entries()) {
        const optimized = preserveOriginal ? file : await optimizeImage(file, logo);
        const body = new FormData();
        body.append("file", optimized);
        if (entity === "projects") {
          body.append("projectName", text("title"));
          body.append("imageIndex", String(index + 1));
        }
        const response = await fetch("/api/admin/upload", { method: "POST", body });
        const result = await response.json() as { url?: string; error?: string };
        if (!response.ok || !result.url) throw new Error(result.error || "Yükleme başarısız.");
        urls.push(result.url);
      }
      setForm((current) => ({
        ...current,
        [fieldName]: multiple
          ? [...(Array.isArray(current[fieldName]) ? current[fieldName] as string[] : []), ...urls]
          : urls[0],
      }));
      if (entity === "projects" && fieldName === "galleryUrls") {
        const nextGallery = [...(Array.isArray(form.galleryUrls) ? form.galleryUrls as string[] : []), ...urls];
        const updatedForm = { ...form, galleryUrls: nextGallery };
        const saveResponse = await fetch("/api/admin/content", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ action: "save", entity: "projects", payload: updatedForm }) });
        const saveResult = await saveResponse.json() as { content?: SiteContent; error?: string };
        if (!saveResponse.ok || !saveResult.content) throw new Error(saveResult.error || "Galeri kaydedilemedi.");
        const savedProject = saveResult.content.projects.find((project) => project.id === String(form.id));
        if (!savedProject || savedProject.galleryUrls.length < nextGallery.length) throw new Error("Galeri sunucuda doğrulanamadı. Lütfen tekrar deneyin.");
        setContent(saveResult.content);
        setForm({ ...savedProject });
        setMessage(`${savedProject.galleryUrls.length} galeri görseli kalıcı olarak kaydedildi.`);
      } else {
        setMessage("Görsel yüklendi. Kaydet düğmesine basın.");
      }
    } catch (error) { setMessage(error instanceof Error ? error.message : "Yükleme başarısız."); }
    finally { setBusy(false); }
  }

  async function save() {
    setBusy(true); setMessage("Kaydediliyor…");
    try {
      const response = await fetch("/api/admin/content", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ action: "save", entity, payload: form }) });
      const result = await response.json() as { content?: SiteContent; error?: string };
      if (!response.ok || !result.content) throw new Error(result.error || "Kayıt başarısız.");
      setContent(result.content);
      if (entity === "projects") {
        const savedProject = result.content.projects.find((project) => project.id === String(form.id));
        if (savedProject) setForm({ ...savedProject });
        setMessage(`Değişiklikler yayınlandı. ${savedProject?.galleryUrls.length ?? 0} galeri görseli kayıtlı.`);
      } else setMessage("Değişiklikler yayınlandı.");
    } catch (error) { setMessage(error instanceof Error ? error.message : "Kayıt başarısız."); }
    finally { setBusy(false); }
  }

  async function remove() {
    if (!form.id || !window.confirm("Bu kaydı silmek istediğinizden emin misiniz?")) return;
    setBusy(true);
    try {
      const response = await fetch("/api/admin/content", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ action: "delete", entity, id: form.id }) });
      const result = await response.json() as { content?: SiteContent; error?: string };
      if (!response.ok || !result.content) throw new Error(result.error || "Silme başarısız.");
      setContent(result.content); setForm(blank(entity)); setMessage("Kayıt silindi.");
    } catch (error) { setMessage(error instanceof Error ? error.message : "Silme başarısız."); }
    finally { setBusy(false); }
  }

  async function persistOrder(nextItems: Record<string, unknown>[]) {
    if (entity === "settings") return;
    const ordered: Record<string, unknown>[] = nextItems.map((item, index) => ({ ...item, sortOrder: index + 1 }));
    setContent((current) => ({ ...current, [entity]: ordered } as SiteContent));
    setForm((current) => {
      const updated = ordered.find((item) => item.id === current.id);
      return updated ? { ...current, sortOrder: updated.sortOrder } : current;
    });
    setBusy(true); setMessage("Yeni sıra kaydediliyor…");
    try {
      const response = await fetch("/api/admin/content", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ action: "reorder", entity, order: ordered.map((item) => item.id) }) });
      const result = await response.json() as { content?: SiteContent; error?: string };
      if (!response.ok || !result.content) throw new Error(result.error || "Sıralama kaydedilemedi.");
      setContent(result.content); setMessage("Yeni sıralama yayınlandı.");
    } catch (error) { setMessage(error instanceof Error ? error.message : "Sıralama kaydedilemedi."); }
    finally { setBusy(false); setDraggedId(null); }
  }

  function dropOn(targetId: string) {
    if (!draggedId || draggedId === targetId) return setDraggedId(null);
    const from = items.findIndex((item) => String(item.id) === draggedId);
    const to = items.findIndex((item) => String(item.id) === targetId);
    if (from < 0 || to < 0) return setDraggedId(null);
    const next = [...items];
    const [moved] = next.splice(from, 1);
    next.splice(to, 0, moved);
    void persistOrder(next);
  }

  function moveItem(index: number, direction: -1 | 1) {
    const target = index + direction;
    if (target < 0 || target >= items.length) return;
    const next = [...items];
    [next[index], next[target]] = [next[target], next[index]];
    void persistOrder(next);
  }

  return <div className="admin-panel">
    <div className="admin-tabs">{(Object.keys(labels) as AdminEntity[]).map((key) => <button className={entity === key ? "active" : ""} key={key} onClick={() => chooseEntity(key)}>{labels[key]}</button>)}</div>
    <div className="admin-body">
      <aside className="admin-list">
        {entity !== "settings" && <><button className="admin-new-button" onClick={() => setForm({ ...blank(entity), sortOrder: items.length + 1 })}>＋ Yeni kayıt</button><p className="admin-sort-help">⋮⋮ simgesinden tutup sürükleyin</p></>}
        {items.map((item, index) => <div className={`admin-list-item${form.id === item.id ? " active" : ""}${draggedId === String(item.id) ? " dragging" : ""}`} draggable={entity !== "settings" && !busy} onDragStart={() => setDraggedId(String(item.id))} onDragOver={(event) => event.preventDefault()} onDrop={() => dropOn(String(item.id))} onDragEnd={() => setDraggedId(null)} key={String(item.id)}>
          {entity !== "settings" && <span className="admin-drag-handle" title="Tut ve sürükle" aria-hidden="true">⋮⋮</span>}
          <button className="admin-list-select" onClick={() => setForm({ ...item })}>{(entity === "projects" || entity === "references") && <span className="admin-list-number">{String(index + 1).padStart(2, "0")}</span>}{String(item.title ?? item.name ?? item.altText ?? "Ana sayfa ayarları")}</button>
          {entity !== "settings" && <span className="admin-move-buttons"><button type="button" disabled={busy || index === 0} onClick={() => moveItem(index, -1)} aria-label="Yukarı taşı">↑</button><button type="button" disabled={busy || index === items.length - 1} onClick={() => moveItem(index, 1)} aria-label="Aşağı taşı">↓</button></span>}
        </div>)}
      </aside>
      <section className="admin-form"><div className="form-grid">
        {entity === "projects" && <>
          <Field label="Proje adı"><input value={text("title")} onChange={(e) => field("title", e.target.value)} /></Field>
          <Field label="Bağlantı adı"><input value={text("slug")} placeholder="Otomatik oluşturulur" onChange={(e) => field("slug", e.target.value)} /></Field>
          <Field label="Durum"><select value={text("status")} onChange={(e) => field("status", e.target.value)}><option value="ongoing">Devam ediyor</option><option value="completed">Tamamlandı</option></select></Field>
          <Field label="Yıl"><input type="number" value={num("year")} onChange={(e) => field("year", Number(e.target.value))} /></Field>
          <Field label="Proje sırası"><input type="number" min="1" value={num("sortOrder")} onChange={(e) => field("sortOrder", Number(e.target.value))} /><small className="field-help">Küçük sayı önce görünür. Örneğin en üstteki proje için 1 yazın.</small></Field>
          <Field label="Başlangıç"><input type="date" value={text("startDate")} onChange={(e) => field("startDate", e.target.value)} /></Field>
          <Field label="Bitiş"><input type="date" value={text("endDate")} onChange={(e) => field("endDate", e.target.value)} /></Field>
          <Field label="Konum"><input value={text("location")} onChange={(e) => field("location", e.target.value)} /></Field>
          <Field label="İşveren"><input value={text("client")} onChange={(e) => field("client", e.target.value)} /></Field>
          <Field label="Kısa açıklama" full><textarea value={text("summary")} onChange={(e) => field("summary", e.target.value)} /></Field>
          <Field label="Detaylı açıklama" full><textarea value={text("description")} onChange={(e) => field("description", e.target.value)} /></Field>
          <Field label="YouTube bağlantısı" full><input type="url" value={text("youtubeUrl")} onChange={(e) => field("youtubeUrl", e.target.value)} /></Field>
          <Field label="Proje web sitesi" full><input type="url" value={text("projectWebsiteUrl")} placeholder="https://proje-web-sitesi.com" onChange={(e) => field("projectWebsiteUrl", e.target.value)} /><small className="field-help">Varsa projenin tanıtım veya resmi web sitesi bağlantısını ekleyin.</small></Field>
          <Field label="Kapak görseli" full><div className="upload-row"><input value={text("coverImageUrl")} onChange={(e) => field("coverImageUrl", e.target.value)} placeholder="Görsel URL" /><input type="file" accept="image/*" onChange={(e) => upload(e.target.files, "coverImageUrl")} /></div></Field>
          <Field label={`Galeri (${Array.isArray(form.galleryUrls) ? form.galleryUrls.length : 0} görsel)`} full>
            <input type="file" accept="image/*" multiple onChange={(e) => upload(e.target.files, "galleryUrls", true)} />
            <small className="field-help">Birden fazla görsel seçebilirsiniz. Görseller performans için otomatik küçültülür; yükleme tamamlanınca “Kaydet ve yayınla” düğmesine basın.</small>
            <div className="admin-media-grid">{(Array.isArray(form.galleryUrls) ? form.galleryUrls as string[] : []).map((url, index) => <div className="admin-media-item" key={`${url}-${index}`}><img src={url} alt={`Galeri ${index + 1}`} /><button type="button" onClick={() => field("galleryUrls", (form.galleryUrls as string[]).filter((_, itemIndex) => itemIndex !== index))}>Kaldır</button></div>)}</div>
          </Field>
          <Field label="Öne çıkar"><label className="upload-row"><input type="checkbox" checked={Boolean(form.featured)} onChange={(e) => field("featured", e.target.checked)} /> Ana sayfada göster</label></Field>
        </>}
        {entity === "services" && <><Field label="Sıra numarası"><input value={text("number")} onChange={(e) => field("number", e.target.value)} /></Field><Field label="Hizmet adı"><input value={text("title")} onChange={(e) => field("title", e.target.value)} /></Field><Field label="Açıklama" full><textarea value={text("summary")} onChange={(e) => field("summary", e.target.value)} /></Field></>}
        {entity === "references" && <><Field label="Firma adı"><input value={text("name")} onChange={(e) => field("name", e.target.value)} /></Field><Field label="Web sitesi"><input value={text("websiteUrl")} onChange={(e) => field("websiteUrl", e.target.value)} /></Field><Field label="Logo" full><div className="upload-row"><input value={text("logoUrl")} onChange={(e) => field("logoUrl", e.target.value)} placeholder="Logo URL" /><input type="file" accept="image/*,.svg" onChange={(e) => upload(e.target.files, "logoUrl", false, true)} /></div><small className="field-help">Önerilen: şeffaf arka planlı SVG veya PNG, yaklaşık 800 × 400 px; dosya en fazla 2 MB.</small></Field><Field label="Öne çıkar"><label className="upload-row"><input type="checkbox" checked={Boolean(form.featured)} onChange={(e) => field("featured", e.target.checked)} /> Referans vitrininde göster</label></Field></>}
        {entity === "fleet" && <><Field label="Makine adı"><input value={text("name")} onChange={(e) => field("name", e.target.value)} /></Field><Field label="Kategori"><input value={text("category")} onChange={(e) => field("category", e.target.value)} /></Field><Field label="Marka / model"><input value={text("brandModel")} onChange={(e) => field("brandModel", e.target.value)} /></Field><Field label="Adet (bilinmiyorsa 0)"><input type="number" min="0" value={num("quantity")} onChange={(e) => field("quantity", Number(e.target.value))} /></Field><Field label="Görsel" full><div className="upload-row"><input value={text("imageUrl")} onChange={(e) => field("imageUrl", e.target.value)} /><input type="file" accept="image/*" onChange={(e) => upload(e.target.files, "imageUrl")} /></div></Field></>}
        {entity === "slides" && <>
          <Field label="Görsel açıklaması"><input value={text("altText")} onChange={(e) => field("altText", e.target.value)} placeholder="Örn. Balmumcu proje sahası" /></Field>
          <Field label="Sıralama"><input type="number" value={num("sortOrder")} onChange={(e) => field("sortOrder", Number(e.target.value))} /></Field>
          <Field label="Slayt görseli" full><div className="upload-row"><input value={text("imageUrl")} onChange={(e) => field("imageUrl", e.target.value)} placeholder="Görsel URL" /><input type="file" accept="image/*" onChange={(e) => upload(e.target.files, "imageUrl")} /></div>{text("imageUrl") && <img className="admin-preview" src={text("imageUrl")} alt="Slayt önizleme" />}</Field>
          <Field label="Yayında"><label className="upload-row"><input type="checkbox" checked={Boolean(form.active)} onChange={(e) => field("active", e.target.checked)} /> Ana sayfa slaytında göster</label></Field>
        </>}
        {entity === "settings" && <>
          <Field label="Üst kısa başlık"><input value={text("heroEyebrow")} onChange={(e) => field("heroEyebrow", e.target.value)} /></Field>
          <Field label="Ana başlık / üst"><input value={text("heroTitleTop")} onChange={(e) => field("heroTitleTop", e.target.value)} /></Field>
          <Field label="Ana başlık / turuncu"><input value={text("heroTitleAccent")} onChange={(e) => field("heroTitleAccent", e.target.value)} /></Field>
          <Field label="Ana başlık / alt"><input value={text("heroTitleBottom")} onChange={(e) => field("heroTitleBottom", e.target.value)} /></Field>
          <Field label="Ana açıklama" full><textarea value={text("heroDescription")} onChange={(e) => field("heroDescription", e.target.value)} /></Field>
          <Field label="Kurumsal bölüm etiketi"><input value={text("introEyebrow")} onChange={(e) => field("introEyebrow", e.target.value)} /></Field>
          <Field label="Kurumsal başlık"><input value={text("introTitle")} onChange={(e) => field("introTitle", e.target.value)} /></Field>
          <Field label="Kurumsal turuncu vurgu"><input value={text("introTitleAccent")} onChange={(e) => field("introTitleAccent", e.target.value)} /></Field>
          <Field label="Kurumsal açıklama" full><textarea value={text("introDescription")} onChange={(e) => field("introDescription", e.target.value)} /></Field>
          <Field label="Hizmetler başlığı"><input value={text("servicesTitle")} onChange={(e) => field("servicesTitle", e.target.value)} /></Field>
          <Field label="Hizmetler turuncu vurgu"><input value={text("servicesTitleAccent")} onChange={(e) => field("servicesTitleAccent", e.target.value)} /></Field>
          <Field label="Projeler başlığı"><input value={text("projectsTitle")} onChange={(e) => field("projectsTitle", e.target.value)} /></Field>
          <Field label="Projeler turuncu vurgu"><input value={text("projectsTitleAccent")} onChange={(e) => field("projectsTitleAccent", e.target.value)} /></Field>
          <Field label="Referanslar başlığı"><input value={text("referencesTitle")} onChange={(e) => field("referencesTitle", e.target.value)} /></Field>
          <Field label="Gerçek kuruluş yılı"><input inputMode="numeric" value={text("foundingYear")} placeholder="Örn. 2008" onChange={(e) => field("foundingYear", e.target.value.replace(/\D/g, "").slice(0, 4))} /><small className="field-help">Yalnızca resmi kayıtlardaki kuruluş yılını girin.</small></Field>
          <Field label="Belge ve sertifikalar" full><textarea value={text("certificatesText")} placeholder="Her belgeyi ayrı satıra yazın" onChange={(e) => field("certificatesText", e.target.value)} /><small className="field-help">Sadece geçerli ve doğrulanmış belgeleri ekleyin.</small></Field>
          <Field label="SEO sayfa başlığı" full><input value={text("seoTitle")} maxLength={70} onChange={(e) => field("seoTitle", e.target.value)} /></Field>
          <Field label="SEO açıklaması" full><textarea value={text("seoDescription")} maxLength={170} onChange={(e) => field("seoDescription", e.target.value)} /></Field>
          <Field label="Google Search Console doğrulama kodu" full><input value={text("googleSiteVerification")} placeholder="Google'ın verdiği content kodu" onChange={(e) => field("googleSiteVerification", e.target.value)} /><small className="field-help">google-site-verification meta etiketindeki content değerini girin.</small></Field>
          <Field label="Kurumsal bölüm başlığı" full><input value={text("corporateTitle")} placeholder="Biz kimiz?" onChange={(e) => field("corporateTitle", e.target.value)} /></Field>
          <Field label="Firma hakkında / tarihçe metni" full><textarea value={text("corporateText")} placeholder="Firmanın kuruluşu, gelişimi, faaliyet alanları ve çalışma anlayışı..." onChange={(e) => field("corporateText", e.target.value)} /><small className="field-help">Kurumsal sayfasındaki “Biz Kimiz?” alanında gösterilir. Yeni paragraf için bir satır boşluk bırakabilirsiniz.</small></Field>
          <Field label="Instagram bağlantısı" full><input type="url" value={text("instagramUrl")} placeholder="https://instagram.com/..." onChange={(e) => field("instagramUrl", e.target.value)} /></Field>
          <Field label="Facebook bağlantısı" full><input type="url" value={text("facebookUrl")} placeholder="https://facebook.com/..." onChange={(e) => field("facebookUrl", e.target.value)} /></Field>
          <Field label="LinkedIn bağlantısı" full><input type="url" value={text("linkedinUrl")} placeholder="https://linkedin.com/company/..." onChange={(e) => field("linkedinUrl", e.target.value)} /></Field>
          <Field label="YouTube bağlantısı" full><input type="url" value={text("youtubeChannelUrl")} placeholder="https://youtube.com/@..." onChange={(e) => field("youtubeChannelUrl", e.target.value)} /></Field>
          <Field label="Üst menü logosu" full><div className="upload-row"><input value={text("headerLogoUrl")} onChange={(e) => field("headerLogoUrl", e.target.value)} /><input type="file" accept="image/*,.svg" onChange={(e) => upload(e.target.files, "headerLogoUrl", false, true)} /></div><small className="field-help">Önerilen: yatay, şeffaf SVG veya PNG; 1500 × 500 px (3:1 oran). Açık arka planda koyu renkli sürüm kullanın.</small></Field>
          <Field label="Amblem / sekme ikonu" full><div className="upload-row"><input value={text("emblemLogoUrl")} onChange={(e) => field("emblemLogoUrl", e.target.value)} /><input type="file" accept="image/png,image/svg+xml,.svg" onChange={(e) => upload(e.target.files, "emblemLogoUrl", false, true, true)} /></div><small className="field-help">Önerilen: kare 512 × 512 px, şeffaf SVG veya PNG. Küçük boyutta okunaklı, yalnız amblem olan sürümü yükleyin.</small></Field>
          <Field label="Alt bölüm logosu" full><small className="field-help">Alt bölümde üst menüye yüklediğiniz aynı ana logo otomatik kullanılır. Böylece site genelinde farklı veya eski logo görünmez.</small></Field>
        </>}
      </div><div className="admin-actions"><button className="save-button" disabled={busy} onClick={save}>Kaydet ve yayınla</button>{entity !== "settings" && <button className="delete-button" disabled={busy} onClick={remove}>Sil</button>}</div>{message && <p className="admin-status" role="status">{message}</p>}</section>
    </div>
  </div>;
}

function Field({ label, full = false, children }: { label: string; full?: boolean; children: React.ReactNode }) { return <div className={`field${full ? " full" : ""}`}><label>{label}</label>{children}</div>; }
